// ── Snaps a day-index to the 1st of its month (DM siempre entra el 1ero) ───
const _snapTo1st = (idx, dates) => {
  if (idx == null || !dates?.length || idx >= dates.length) return idx;
  const date = new Date(dates[idx] + "T12:00:00");
  if (date.getDate() === 1) return idx; // ya es el 1ero
  const firstStr = `${date.getFullYear()}-${String(date.getMonth()+1).padStart(2,"0")}-01`;
  const found = dates.indexOf(firstStr);
  if (found !== -1) return found;
  const nextMonth = new Date(date.getFullYear(), date.getMonth()+1, 1);
  const nextStr = nextMonth.toISOString().slice(0,10);
  const foundNext = dates.indexOf(nextStr);
  return foundNext !== -1 ? foundNext : idx;
};

const TRACKS_CFG = [
  // ── NTVG 2 catalog (distribuidora: Downtown) ──
  ...Object.entries(RAW_STREAM_DATA).map(([id, t]) => {
    const dm = _DM_CONFIG[id] || {};
    // DM siempre entra el 1ero de cada mes — snap índice al 1ero si no lo es
    const rawStart = dm.dmStart ?? null;
    const rawEnd   = dm.dmEnd   ?? null;
    const _artistMap = {"NTVG 2":"Downtown","Florece":"DPR"};
    return {
      id, name: t.name, artist: _artistMap[t.artist] ?? t.artist ?? "Downtown",
      genre: "Rock Alternativo", royalty: 0.0011,
      status:  dm.status  ?? "none",
      dmStart: _snapTo1st(rawStart, t.dates),
      dmEnd:   _snapTo1st(rawEnd,   t.dates),
      sources: { editorial: 20, algorithmic: 42, playlists: 25, profile: 13 },
    };
  }),
  // ── FLORECE EN EL CAOS ──
  ...Object.entries(RAW_STREAM_DATA_FLORECE).map(([id, t]) => {
    // Resolve DM config by track name → date → day index
    const dmCfg = _FLORECE_DM[t.name] || {};
    let dmStart = null, dmEnd = null, status = dmCfg.status ?? "none";
    if (dmCfg.dmStartDate && t.dates?.length) {
      dmStart = t.dates.indexOf(dmCfg.dmStartDate);
      if (dmStart === -1) dmStart = t.dates.findIndex(d => d >= dmCfg.dmStartDate);
      if (dmStart === -1) dmStart = null;
    }
    if (dmCfg.dmEndDate && t.dates?.length) {
      dmEnd = t.dates.indexOf(dmCfg.dmEndDate);
      if (dmEnd === -1) dmEnd = t.dates.findIndex(d => d >= dmCfg.dmEndDate);
      if (dmEnd === -1) dmEnd = null;
    }
    // Resolve optional pause/resume indices for multi-period DM
    let dmPauseIdx = null, dmResumeIdx = null;
    if (dmCfg.dmPause && t.dates?.length) {
      dmPauseIdx = t.dates.indexOf(dmCfg.dmPause);
      if (dmPauseIdx === -1) dmPauseIdx = t.dates.findIndex(d => d >= dmCfg.dmPause);
      if (dmPauseIdx === -1) dmPauseIdx = null;
    }
    if (dmCfg.dmResume && t.dates?.length) {
      dmResumeIdx = t.dates.indexOf(dmCfg.dmResume);
      if (dmResumeIdx === -1) dmResumeIdx = t.dates.findIndex(d => d >= dmCfg.dmResume);
      if (dmResumeIdx === -1) dmResumeIdx = null;
    }
    return {
      id, name: t.name, artist: "DPR",
      genre: "Rock Alternativo", royalty: 0.0011,
      status, dmStart, dmEnd, dmPauseIdx, dmResumeIdx,
      sources: { editorial: 20, algorithmic: 42, playlists: 25, profile: 13 },
    };
  }),
];

// ── Helpers de limpieza ───────────────────────────────────────────

const _normName = (n) => n
  .toLowerCase()
  .replace(/\s*\(feat\..*?\)/gi, "")
  .replace(/\s*-\s*en vivo.*/gi, "")
  .replace(/[áàä]/g,"a").replace(/[éèë]/g,"e")
  .replace(/[íìï]/g,"i").replace(/[óòö]/g,"o")
  .replace(/[úùü]/g,"u")
  .replace(/[^a-z0-9]/g,"")
  .trim();

// Suavizado de anomalías: reemplaza spikes con valor anterior cuando no hay DM activo
// threshold = cuántas veces el mediana de ventana para ser considerado spike
const _smoothAnomalies = (arr, dmStart, threshold = 4, window = 7) => {
  const out = [...arr];
  for (let i = 1; i < out.length; i++) {
    const inDM = dmStart != null && i >= dmStart;
    if (inDM) continue;
    const lo = Math.max(0, i - window);
    const hi = Math.min(out.length, i + window + 1);
    const neighbors = [...out.slice(lo, i), ...out.slice(i + 1, hi)].filter(v => v > 0);
    if (neighbors.length === 0) continue;
    neighbors.sort((a, b) => a - b);
    const med = neighbors[Math.floor(neighbors.length / 2)];
    if (med > 0 && out[i] > med * threshold) {
      out[i] = out[i - 1]; // reemplaza con día anterior
    }
  }
  return out;
};

// Filtro de mediana para popularity (oscilaciones API)
const _medianFilter = (arr, half = 2) => {
  return arr.map((_, i) => {
    const lo = Math.max(0, i - half);
    const hi = Math.min(arr.length, i + half + 1);
    const w = arr.slice(lo, hi).filter(v => v > 0).sort((a, b) => a - b);
    return w.length ? w[Math.floor(w.length / 2)] : arr[i];
  });
};

// Aplica limpieza al RAW_STREAM_DATA in-place
for (const [id, raw] of Object.entries(RAW_STREAM_DATA)) {
  const dm = _DM_CONFIG[id];
  const dmStart = dm?.dmStart ?? null;
  if (raw.streams) raw.streams = _smoothAnomalies(raw.streams, dmStart, 4, 7);
  if (raw.popularity) raw.popularity = _medianFilter(raw.popularity, 2);
}
// Aplica limpieza al RAW_STREAM_DATA_FLORECE in-place
for (const [id, raw] of Object.entries(RAW_STREAM_DATA_FLORECE)) {
  const cfg = TRACKS_CFG.find(t => t.id === id);
  const dmStart = cfg?.dmStart ?? null;
  if (raw.streams) raw.streams = _smoothAnomalies(raw.streams, dmStart, 4, 7);
}

// ── Deduplicación: unifica streams de versiones del mismo track ──
const _dedupedTracks = (() => {
  const groups = {};
  for (const t of TRACKS_CFG) {
    const key = t.artist + "|" + _normName(t.name);
    if (!groups[key]) groups[key] = [];
    groups[key].push(t);
  }

  const result = [];
  for (const [, group] of Object.entries(groups)) {
    if (group.length === 1) {
      result.push(group[0]);
      continue;
    }
    // Elegir el track con mayor peak reciente como "principal"
    const peak = (t) => Math.max(...((RAW_STREAM_DATA[t.id] ?? RAW_STREAM_DATA_FLORECE[t.id])?.streams?.slice(-30) ?? [0]));
    group.sort((a, b) => peak(b) - peak(a));
    const main = group[0];

    // Cada Spotify ID es una grabación distinta — no sumar entradas secundarias.
    // Usamos sólo el track principal (mayor peak reciente); el fingerprint evita data duplicada.
    // Fingerprint para detectar duplicados exactos (misma data reportada distinto ID)
    const _fp = (id) => {
      const s = (RAW_STREAM_DATA[id] ?? RAW_STREAM_DATA_FLORECE[id])?.streams ?? [];
      return s.slice(0,5).join(",") + "|" + s.slice(-5).join(",");
    };
    const seenFp = new Set();
    const dateMap = {};
    for (const t of group) {
      const raw = RAW_STREAM_DATA[t.id] ?? RAW_STREAM_DATA_FLORECE[t.id];
      if (!raw) continue;
      // Cada Spotify ID es una grabación distinta — nunca sumar entradas secundarias.
      // Sólo se procesa el track principal (el de mayor peak reciente).
      if (t.id !== main.id) continue;
      // Excluir duplicados exactos (mismo fingerprint ya incluido)
      const fp = _fp(t.id);
      if (seenFp.has(fp)) continue;
      seenFp.add(fp);
      raw.dates.forEach((date, i) => {
        dateMap[date] = (dateMap[date] ?? 0) + (raw.streams[i] ?? 0);
      });
    }
    const dates = Object.keys(dateMap).sort();
    const streams = dates.map(d => dateMap[d]);

    // Escribir el resultado unificado en RAW_STREAM_DATA bajo el ID principal
    RAW_STREAM_DATA[main.id] = {
      ...RAW_STREAM_DATA[main.id],
      dates,
      streams,
    };

    result.push(main);
  }
  return result;
})();

// Reemplazar TRACKS_CFG con la versión deduplicada
TRACKS_CFG.length = 0;
_dedupedTracks.forEach(t => TRACKS_CFG.push(t));


// ════════════════════════════════════════════════════════════════
//  BUILD HISTORY FROM REAL DATA
// ════════════════════════════════════════════════════════════════
const buildHistoryFromReal = (tid, rawOverride = null) => {
  const raw = rawOverride ?? RAW_STREAM_DATA[tid] ?? RAW_STREAM_DATA_FLORECE[tid];
  if (!raw) return [];
  // Trim trailing zeros (días incompletos, ej. el día de hoy sin data final)
  let endIdx = raw.streams.length;
  while (endIdx > 0 && (raw.streams[endIdx - 1] === 0 || raw.streams[endIdx - 1] == null)) endIdx--;
  const progArr = raw.programmedStreams ?? [];
  return raw.dates.slice(0, endIdx).map((date, i) => {
    const d = new Date(date + "T12:00:00");
    const dow = d.getDay();
    return {
      day: i, dow, streams: raw.streams[i],
      programmedStreams: progArr[i] ?? 0,
      date, label: d.toLocaleDateString("en-US", { month:"short", day:"numeric" }),
      baseline: null, ci_lo: null, ci_hi: null,
    };
  });
};

// ════════════════════════════════════════════════════════════════
//  EWLS BASELINE — dual model: total (DM lift) + organic (post-DM floor)
// ════════════════════════════════════════════════════════════════
// Helper: fit EWLS on an array of numeric values aligned to trainRaw
const _fitEWLS = (trainRaw, streamVals) => {
  const sorted = [...streamVals].sort((a,b) => a-b);
  const p97 = sorted[Math.min(Math.floor(sorted.length * 0.97), sorted.length-1)];
  const capped = streamVals.map(v => Math.min(v, p97));
  const lam = Math.log(2) / CFG.HALF_LIFE;
  const w = trainRaw.map((_, i) => Math.exp(-lam * (trainRaw.length - 1 - i)));
  const wSum = w.reduce((a,b) => a+b, 0);
  const nw = w.map(x => x / wSum);
  const logS = capped.map(v => Math.log(v + 1));
  const wMx = trainRaw.reduce((s,d,i) => s + d.day * nw[i], 0);
  const wMl = logS.reduce((s,v,i) => s + v * nw[i], 0);
  let slopeL = 0;
  if (trainRaw.length >= 28) {
    const num = trainRaw.reduce((s,d,i) => s + nw[i]*(d.day-wMx)*(logS[i]-wMl), 0);
    const den = trainRaw.reduce((s,d,i) => s + nw[i]*(d.day-wMx)**2, 0);
    slopeL = den > 0 ? num/den : 0;
    const maxSlopeL = 0.05/7;
    slopeL = Math.max(-maxSlopeL, Math.min(maxSlopeL, slopeL));
  }
  const dowS = new Array(7).fill(0), dowC = new Array(7).fill(0);
  trainRaw.forEach((d,i) => {
    const pred = wMl + slopeL*(d.day-wMx);
    dowS[d.dow] += (logS[i]-pred)*nw[i]; dowC[d.dow] += nw[i];
  });
  const rawDow = dowS.map((s,i) => dowC[i]>0 ? s/dowC[i] : 0);
  const meanDow = rawDow.reduce((a,b)=>a+b,0)/7;
  const dow7L = rawDow.map(c => (c-meanDow)*CFG.RIDGE);
  const resid = trainRaw.map((d,i) => logS[i]-(wMl+slopeL*(d.day-wMx)+dow7L[d.dow]));
  const stdR = Math.sqrt(resid.reduce((s,r)=>s+r*r,0)/resid.length);
  return { wMl, wMx, slopeL, dow7L, stdR };
};

const computeBaseline = (history, dmStart) => {
  if (dmStart == null)
    return history.map(d => ({ ...d, baseline:d.streams, baselineOrg:d.streams, ci_lo:d.streams, ci_hi:d.streams }));

  const TRAIN_EXT = 90;
  const ANCHOR_WIN = 15;
  const tStart = Math.max(0, dmStart - TRAIN_EXT);
  const trainRaw = history.slice(tStart, dmStart);
  if (trainRaw.length < 7)
    return history.map(d => ({ ...d, baseline:d.streams, baselineOrg:d.streams, ci_lo:d.streams, ci_hi:d.streams }));

  // ── Fit EWLS to extract slope + DOW patterns (ignore centroid level) ──
  const mTotal = _fitEWLS(trainRaw, trainRaw.map(d => d.streams));
  const orgVals = trainRaw.map(d => Math.max(1, d.streams - (d.programmedStreams ?? 0)));
  const mOrg   = _fitEWLS(trainRaw, orgVals);

  // ── Anchor A: exp-weighted avg of last ANCHOR_WIN total streams before DM ──
  //    Half-life 5d → recent days dominate, smooths last-day noise
  const anchorWin = history.slice(Math.max(0, dmStart - ANCHOR_WIN), dmStart);
  const anchorLam = Math.log(2) / 5;
  const anchorW   = anchorWin.map((_, i) => Math.exp(-anchorLam * (anchorWin.length - 1 - i)));
  const anchorWSum = anchorW.reduce((a,b) => a+b, 0);
  const anchorTotal = Math.max(1, Math.round(
    anchorWin.reduce((s,d,i) => s + d.streams * anchorW[i], 0) / anchorWSum
  ));
  const anchorTotalL = Math.log(anchorTotal + 1);

  // ── Anchor B: same for organic streams ──
  const anchorOrg = Math.max(1, Math.round(
    anchorWin.reduce((s,d,i) => s + Math.max(1, d.streams-(d.programmedStreams??0)) * anchorW[i], 0) / anchorWSum
  ));
  const anchorOrgL = Math.log(anchorOrg + 1);

  // ── Anchor day (last pre-DM day) ──
  const anchorDayVal = history[dmStart - 1]?.day ?? (history[dmStart]?.day ?? 0) - 1;

  return history.map((d, i) => {
    // Before DM: baseline = actual (no DM effect → lift = 0 in pre-DM by design)
    if (i < dmStart) {
      return { ...d, baseline: d.streams, baselineOrg: Math.max(1, d.streams-(d.programmedStreams??0)),
               ci_lo: d.streams, ci_hi: d.streams };
    }
    // During / after DM: project from anchor using slope + DOW
    const dfa = d.day - anchorDayVal;
    // A: Total contrafactual
    const blL  = anchorTotalL + mTotal.slopeL * dfa + mTotal.dow7L[d.dow];
    const bl   = Math.max(Math.round(Math.exp(blL) - 1), Math.round(anchorTotal * 0.05));
    const horizon = i - dmStart;
    const ci   = CFG.CI * mTotal.stdR * Math.sqrt(1 + horizon / trainRaw.length);
    // B: Organic floor
    const blOrgL = anchorOrgL + mOrg.slopeL * dfa + mOrg.dow7L[d.dow];
    const blOrg  = Math.max(Math.round(Math.exp(blOrgL) - 1), Math.round(anchorOrg * 0.05));

    return {
      ...d,
      baseline:    bl,
      baselineOrg: blOrg,
      ci_lo: Math.round(Math.max(Math.exp(blL - ci) - 1, 0)),
      ci_hi: Math.round(Math.exp(blL + ci) - 1),
    };
  });
};

// ════════════════════════════════════════════════════════════════
//  BASELINE FORECAST — Hybrid: recent anchor + recentK decay + DOW + CI
//  Anchors on exp-weighted avg of last 15 organic days,
//  applies recentK (28-day decay slope) for projection,
//  corrects for day-of-week patterns from recent 28 days,
//  and estimates CI from residual variance of that window.
// ════════════════════════════════════════════════════════════════
const appendForecast = (history) => {
  if (history.length < 14) return history;

  // ── 1. Recent window: last 28 days (for decay + dow), last 15 for anchor ──
  const ANCHOR_WIN = 15;
  const RECENT_WIN = 28;
  const recent28 = history.slice(-Math.min(RECENT_WIN, history.length));
  const recent15 = history.slice(-Math.min(ANCHOR_WIN, history.length));

  // Organic streams (total − programmed) to avoid algo inflation
  const org28 = recent28.map(d => Math.max(1, d.streams - (d.programmedStreams ?? 0)));
  const org15 = recent15.map(d => Math.max(1, d.streams - (d.programmedStreams ?? 0)));

  // ── 2. Anchor: exp-weighted average of last 15 organic days ──
  //    Half-life 5 days → recent days dominate, but smooths spikes
  const anchorLam = Math.log(2) / 5;
  const aw = org15.map((_, i) => Math.exp(-anchorLam * (org15.length - 1 - i)));
  const awSum = aw.reduce((a,b) => a+b, 0);
  const anchorStreams = Math.max(1, Math.round(org15.reduce((s, v, i) => s + v * aw[i], 0) / awSum));
  const anchorL = Math.log(anchorStreams + 1);

  // ── 3. Decay rate: recentK from last 28 days (log-linear regression) ──
  const logOrg28 = org28.map(v => Math.log(v + 1));
  const rn = org28.length, rMx = (rn - 1) / 2;
  const rMl = logOrg28.reduce((s, v) => s + v, 0) / rn;
  const rNum = logOrg28.reduce((s, v, i) => s + (i - rMx) * (v - rMl), 0);
  const rDen = logOrg28.reduce((s, _, i) => s + (i - rMx) ** 2, 0);
  // Negative slope = decay; clamp to prevent extreme projections
  let decaySlope = rDen > 0 ? rNum / rDen : 0;
  const maxSlope = 0.05 / 7; // cap ~0.7%/day
  decaySlope = Math.max(-maxSlope, Math.min(maxSlope, decaySlope));

  // ── 4. Day-of-week correction from recent 28 days ──
  const dowS = new Array(7).fill(0), dowC = new Array(7).fill(0);
  recent28.forEach((d, i) => {
    const pred = rMl + decaySlope * (i - rMx);
    const residDow = logOrg28[i] - pred;
    dowS[d.dow] += residDow;
    dowC[d.dow] += 1;
  });
  const rawDow = dowS.map((s, i) => dowC[i] > 0 ? s / dowC[i] : 0);
  const meanDow = rawDow.reduce((a, b) => a + b, 0) / 7;
  const dow7L = rawDow.map(c => (c - meanDow) * CFG.RIDGE);

  // ── 5. CI: residual std from recent 28 days ──
  const resid = recent28.map((d, i) => logOrg28[i] - (rMl + decaySlope * (i - rMx) + dow7L[d.dow]));
  const stdR = Math.sqrt(resid.reduce((s, r) => s + r * r, 0) / resid.length);

  // ── 6. Generate forecast ──
  const lastPt = history.at(-1);
  const forecast = [];
  for (let i = 1; i <= CFG.FORECAST_DAYS; i++) {
    const fDay = lastPt.day + i;
    const fDow = (lastPt.dow + i) % 7;
    // Project from anchor using decay slope + dow correction
    const blL = anchorL + decaySlope * i + dow7L[fDow];
    const bl = Math.max(Math.round(Math.exp(blL) - 1), Math.round(anchorStreams * 0.05));
    // CI widens with horizon
    const ci = CFG.CI * stdR * Math.sqrt(1 + i / rn);
    const fDate = new Date(lastPt.date + 'T12:00:00');
    fDate.setDate(fDate.getDate() + i);
    const mm = fDate.getMonth() + 1, dd = fDate.getDate();
    forecast.push({
      day: fDay, dow: fDow, streams: null,
      date: fDate.toISOString().slice(0, 10),
      label: `${mm}/${dd}`, isForecast: true,
      baseline: bl,
      ci_lo: Math.round(Math.max(Math.exp(blL - ci) - 1, 0)),
      ci_hi: Math.round(Math.exp(blL + ci) - 1),
    });
  }
  return [...history, ...forecast];
};

// ════════════════════════════════════════════════════════════════
//  DECAY METRICS
// ════════════════════════════════════════════════════════════════
const calcMetrics = (history) => {
  if (history.length < 14) return null;
  const peak = Math.max(...history.map(d => d.streams));
  // Use post-peak window for structural decay (tracks in growth phase have k≈0)
  const peakIdx = history.findIndex(d => d.streams === peak);
  const postPeak = history.slice(peakIdx);
  const eff = postPeak.length >= 14
    ? postPeak.slice(0, Math.min(60, postPeak.length))
    : history.slice(0, Math.min(60, history.length));
  const n = eff.length, mX = (n-1)/2;
  const mY = eff.reduce((s,d)=>s+Math.log(Math.max(d.streams,1)),0)/n;
  const numK = eff.reduce((s,d,i)=>s+(i-mX)*(Math.log(Math.max(d.streams,1))-mY),0);
  const denK = eff.reduce((s,_,i)=>s+(i-mX)**2,0);
  const structK = Math.max(0, -(denK>0?numK/denK:0));
  const rec = history.slice(-Math.min(28,history.length));
  const rn = rec.length, rMx=(rn-1)/2;
  const rMy = rec.reduce((s,d)=>s+Math.log(Math.max(d.streams,1)),0)/rn;
  const rNum = rec.reduce((s,d,i)=>s+(i-rMx)*(Math.log(Math.max(d.streams,1))-rMy),0);
  const rDen = rec.reduce((s,_,i)=>s+(i-rMx)**2,0);
  const recentK = Math.max(0, -(rDen>0?rNum/rDen:0));
  const halfLife = structK>0 ? +(Math.log(2)/structK/7).toFixed(1) : 999;
  const recAvg = rec.reduce((s,d)=>s+d.streams,0)/rec.length;
  const organicFloor = +((recAvg/peak)*100).toFixed(1);
  const prev4w = history.slice(-Math.min(56,history.length), -Math.min(28,history.length));
  const prevAvg = prev4w.length ? prev4w.reduce((s,d)=>s+d.streams,0)/prev4w.length : recAvg;
  const mom4w = +(((recAvg-prevAvg)/prevAvg)*100).toFixed(1);
  return {
    structK:+structK.toFixed(4), recentK:+recentK.toFixed(4),
    halfLife, organicFloor, mom4w, peak,
    current:history.at(-1)?.streams??0, avgStreams:Math.round(recAvg),
  };
};

// ════════════════════════════════════════════════════════════════
//  BUILD CATALOG
// ════════════════════════════════════════════════════════════════
const buildCatalog = (liveData = {}) => TRACKS_CFG.map(cfg => {
  const liveRaw = liveData[cfg.id] ?? null;
  const raw = liveRaw ?? RAW_STREAM_DATA[cfg.id] ?? RAW_STREAM_DATA_FLORECE[cfg.id];
  if (!raw) return null;
  const histRaw = buildHistoryFromReal(cfg.id, liveRaw);
  const history = computeBaseline(histRaw, cfg.dmStart);
  const metrics = calcMetrics(history);
  let dm = { liftPct:null, incremental:null, gross:null, commission:null, net:null, observed:0, baseline:0, noBaseline:false };
  if (cfg.dmStart != null) {
    const trainLen = Math.min(cfg.dmStart, CFG.TRAIN_DAYS);
    const hasBaseline = trainLen >= 7;
    const campFull = history.slice(cfg.dmStart, cfg.dmEnd ?? history.length);
    // Exclude paused period if present (dmPauseIdx..dmResumeIdx)
    const camp = (cfg.dmPauseIdx != null && cfg.dmResumeIdx != null)
      ? campFull.filter((_,i) => {
          const absIdx = cfg.dmStart + i;
          return absIdx < cfg.dmPauseIdx || absIdx >= cfg.dmResumeIdx;
        })
      : campFull;
    const obs = camp.reduce((s,d)=>s+d.streams,0);
    const bl  = camp.reduce((s,d)=>s+(d.baseline??d.streams),0);
    const inc = obs - bl;
    // Desglose algorítmico/orgánico durante la campaña
    const campProgObs = camp.reduce((s,d)=>s+(d.programmedStreams??0),0);
    const campOrgObs  = obs - campProgObs;
    // Paused period stats (for display)
    const pausedSlice = (cfg.dmPauseIdx != null && cfg.dmResumeIdx != null)
      ? history.slice(cfg.dmPauseIdx, cfg.dmResumeIdx) : [];
    const pausedDays = pausedSlice.length;
    const pausedStreams = pausedSlice.reduce((s,d) => s + d.streams, 0);
    const algoRatio   = obs > 0 ? campProgObs / obs : 0;
    const algoInc     = hasBaseline ? Math.round(inc * algoRatio) : null;
    const orgInc      = hasBaseline ? Math.round(inc * (1 - algoRatio)) : null;
    // Cambio real de streams algorítmicos: pre-DM avg/día vs durante-DM avg/día
    const preDmSlice = history.slice(Math.max(0, (cfg.dmStart??0) - 30), cfg.dmStart??0);
    const preDmAlgoAvg = preDmSlice.length > 0
      ? preDmSlice.reduce((s,d) => s + (d.programmedStreams??0), 0) / preDmSlice.length : 0;
    const campAlgoAvg = camp.length > 0 ? campProgObs / camp.length : 0;
    const algoDelta = preDmAlgoAvg > 0 ? +((campAlgoAvg / preDmAlgoAvg - 1) * 100).toFixed(1) : null;
    const algoDeltaAbs = Math.round(campAlgoAvg - preDmAlgoAvg);
    // Canibalización: streams que pasaron de orgánico a algorítmico sin crecer el total
    const preDmTotalAvg = preDmSlice.length > 0
      ? preDmSlice.reduce((s,d) => s + d.streams, 0) / preDmSlice.length : 0;
    const campTotalAvg = camp.length > 0 ? obs / camp.length : 0;
    const algoGrowthPerDay = campAlgoAvg - preDmAlgoAvg;
    const totalGrowthPerDay = campTotalAvg - preDmTotalAvg;
    const cannibalizedPerDay = Math.max(0, algoGrowthPerDay - Math.max(0, totalGrowthPerDay));
    const cannibalized = Math.round(cannibalizedPerDay * camp.length);
    const cannibalizationCost = cannibalized > 0 ? +(cannibalized * cfg.royalty * CFG.DM_CUT).toFixed(2) : 0;
    const gross = hasBaseline ? inc * cfg.royalty : null;
    const algoGross = algoInc != null ? +(algoInc * cfg.royalty).toFixed(2) : null;
    const orgGross  = orgInc  != null ? +(orgInc  * cfg.royalty).toFixed(2) : null;
    // Discovery Mode cobra 30% sobre TODOS los streams algorítmicos (no solo incrementales)
    const comm = +(campProgObs * cfg.royalty * CFG.DM_CUT).toFixed(2);
    // Post-DM: compare avg streams during DM vs after leaving DM (completed tracks only)
    const postDmSlice = cfg.dmEnd != null ? history.slice(cfg.dmEnd) : [];
    const dmAvg      = camp.length > 0 ? +(obs / camp.length).toFixed(0) : null;
    const postDmAvg  = postDmSlice.length > 0
      ? +(postDmSlice.reduce((s,d)=>s+d.streams,0) / postDmSlice.length).toFixed(0)
      : null;
    const postDmDelta = (postDmAvg != null && dmAvg != null && dmAvg > 0)
      ? +((postDmAvg / dmAvg - 1) * 100).toFixed(1)
      : null;
    // net = gross revenue (incremental) minus commission on ALL algo streams
    const net = gross != null ? +(gross - comm).toFixed(2) : null;
    // Per-period stats for multi-period DM (pause/resume)
    let dmPeriods = null;
    if (cfg.dmPauseIdx != null && cfg.dmResumeIdx != null) {
      const _periodStats = (campSlice) => {
        if (!campSlice.length) return null;
        const obsP = campSlice.reduce((s,d) => s + d.streams, 0);
        const blP  = campSlice.reduce((s,d) => s + (d.baseline ?? d.streams), 0);
        const incP = obsP - blP;
        const progP = campSlice.reduce((s,d) => s + (d.programmedStreams ?? 0), 0);
        const commP = +(progP * cfg.royalty * CFG.DM_CUT).toFixed(2);
        const grossP = hasBaseline ? +(incP * cfg.royalty).toFixed(2) : null;
        const netP = grossP != null ? +(grossP - commP).toFixed(2) : null;
        const liftP = hasBaseline && blP > 0 ? +((incP/blP)*100).toFixed(1) : null;
        return { obs: obsP, inc: Math.round(incP), liftPct: liftP, net: netP, days: campSlice.length };
      };
      const camp1 = history.slice(cfg.dmStart, cfg.dmPauseIdx);
      const camp2 = history.slice(cfg.dmResumeIdx, cfg.dmEnd ?? history.length);
      dmPeriods = [
        { period: 1, status: "completed",
          startDate: history[cfg.dmStart]?.date,
          endDate:   history[cfg.dmPauseIdx - 1]?.date ?? history[cfg.dmPauseIdx]?.date,
          ..._periodStats(camp1) },
        { period: 2, status: "active",
          startDate: history[cfg.dmResumeIdx]?.date,
          endDate:   cfg.dmEnd != null ? history[cfg.dmEnd - 1]?.date : null,
          ..._periodStats(camp2) },
      ].filter(p => p.obs != null);
    }
    dm = {
      liftPct:     hasBaseline && bl>0 ? +((inc/bl)*100).toFixed(1) : null,
      incremental: hasBaseline ? Math.round(inc) : null,
      gross:       gross != null ? +gross.toFixed(2) : null,
      commission:  +comm.toFixed(2),
      net,
      observed: obs, baseline: bl,
      campProgObs, campOrgObs, algoRatio: +algoRatio.toFixed(3),
      algoInc, orgInc, algoGross, orgGross,
      algoDelta, algoDeltaAbs, preDmAlgoAvg: Math.round(preDmAlgoAvg), campAlgoAvg: Math.round(campAlgoAvg),
      noBaseline: !hasBaseline,
      dmAvg, postDmAvg, postDmDelta,
      pausedDays, pausedStreams,
      cannibalized, cannibalizationCost,
      dmPeriods,
    };
  }
  // Auto-detect candidatos: tracks con decay real y volumen suficiente
  let effectiveStatus = cfg.status;
  if (effectiveStatus === "none" && metrics) {
    const hasVolume  = metrics.avgStreams >= CANDIDATE_CFG.minAvgStreams;
    const hasDecay   = metrics.organicFloor <= CANDIDATE_CFG.maxOrgFloor
                    || metrics.mom4w        <= CANDIDATE_CFG.maxMom4w;
    if (hasVolume && hasDecay) effectiveStatus = "candidate";
  }
  // Popularity data
  const popLookup = {};
  if (raw.pop_dates) {
    raw.pop_dates.forEach((d, i) => { popLookup[d] = raw.popularity[i]; });
  }
  const popVals = raw.popularity ?? [];
  const popCurrent = popVals.length ? popVals.at(-1) : null;
  const popRecent  = popVals.slice(-4);
  const popEarly   = popVals.slice(0, 4);
  const popTrend   = (popRecent.length && popEarly.length)
    ? +((popRecent.reduce((s,v)=>s+v,0)/popRecent.length) - (popEarly.reduce((s,v)=>s+v,0)/popEarly.length)).toFixed(1)
    : 0;
  const popMetrics = popCurrent !== null
    ? { current: popCurrent, trend: popTrend, lookup: popLookup }
    : null;
  return { ...cfg, status: effectiveStatus, name:raw.name, history, metrics, dm, popMetrics };
}).filter(Boolean);

const CATALOG = buildCatalog();

// ════════════════════════════════════════════════════════════════
//  SIMILAR TRACKS (pattern matching)
// ════════════════════════════════════════════════════════════════
const findSimilarTracks = (track, catalog, n = 6) => {
  if (!track?.metrics) return [];
  const m = track.metrics;
  const nK  = v => Math.min((v ?? 0) / 0.06, 1);
  const nFl = v => Math.min((v ?? 0) / 100, 1);
  const nMo = v => (Math.min(Math.max(v ?? 0, -60), 60) + 60) / 120;
  const nSt = v => Math.min((v ?? 0) / 60000, 1);
  const W   = [0.35, 0.30, 0.20, 0.15];
  const cv  = [nK(m.structK), nFl(m.organicFloor), nMo(m.mom4w), nSt(m.avgStreams)];
  return catalog
    .filter(t => t.id !== track.id && t.metrics)
    .map(t => {
      const tm = t.metrics;
      const tv = [nK(tm.structK), nFl(tm.organicFloor), nMo(tm.mom4w), nSt(tm.avgStreams)];
      const dist = Math.sqrt(W.reduce((s, w, i) => s + w * (tv[i] - cv[i]) ** 2, 0));
      return { ...t, _sim: Math.round((1 - Math.min(dist, 1)) * 100) };
    })
    .sort((a, b) => b._sim - a._sim)
    .slice(0, n);
};

// ════════════════════════════════════════════════════════════════
//  LIFECYCLE DETECTION
// ════════════════════════════════════════════════════════════════
const detectLifecycle = (track) => {
  const m = track.metrics;
  if (!m) return { stage: "unknown", label: "Desconocido", color: "slate", desc: "" };
  const history = track.history ?? [];
  const peakIdx = history.findIndex(d => d.streams === m.peak);
  const daysSincePeak = history.length - peakIdx - 1;
  const currentVal = history.at(-1)?.streams ?? 0;
  const currentPct = m.peak > 0 ? (currentVal / m.peak) * 100 : 0;
  // Launch: still in growth or just peaked (≤21d past peak, positive momentum)
  if (daysSincePeak <= 21 && m.mom4w >= 0) {
    return { stage: "launch", label: "🚀 Lanzamiento", color: "cyan",
      desc: `Día ${peakIdx + 1} de vida · en curva de ascenso` };
  }
  // Peak zone: peaked ≤42d ago and still high
  if (daysSincePeak <= 42 && currentPct >= 40) {
    return { stage: "peak", label: "⭐ Pico", color: "yellow",
      desc: `Pico hace ${daysSincePeak}d · ${currentPct.toFixed(0)}% del máximo` };
  }
  // Decay activo: meaningful structural decay with k > threshold
  if (m.structK > 0.005 && currentPct >= 15 && m.halfLife < 999) {
    return { stage: "decay", label: "📉 Decay Activo", color: "amber",
      desc: `k=${m.structK.toFixed(4)} · half-life ${m.halfLife}w · ${currentPct.toFixed(0)}% del pico` };
  }
  // Long-tail: low k, settled floor
  if (currentPct >= 8 && m.structK <= 0.015) {
    return { stage: "longtail", label: "📊 Long-tail", color: "indigo",
      desc: `Estabilizado en ${currentPct.toFixed(0)}% del pico · decay lento` };
  }
  // Dormant: very low relative to peak
  return { stage: "dormant", label: "💤 Dormant", color: "slate",
    desc: `${currentPct.toFixed(0)}% del pico · sin momentum` };
};

// ════════════════════════════════════════════════════════════════
//  CATALOG DM OUTCOME ANALYSIS
// ════════════════════════════════════════════════════════════════
const analyzeCatalogDM = (catalog) => {
  const withDM = (catalog ?? []).filter(t => t.dmStart != null && t.dm?.liftPct != null && t.metrics);
  if (withDM.length === 0) return { n: 0, successRate: null, avgLiftSuccess: null, successProfile: null, poorProfile: null };
  const successful = withDM.filter(t => t.dm.liftPct >= 15);
  const poor       = withDM.filter(t => t.dm.liftPct < 5);
  const avg = (arr, fn) => arr.length ? arr.reduce((s, t) => s + fn(t), 0) / arr.length : null;
  const successProfile = successful.length ? {
    avgK:    avg(successful, t => t.metrics.structK),
    avgFloor:avg(successful, t => t.metrics.organicFloor),
    avgMom:  avg(successful, t => t.metrics.mom4w),
    avgLift: avg(successful, t => t.dm.liftPct),
    n:       successful.length,
  } : null;
  const poorProfile = poor.length ? {
    avgK:    avg(poor, t => t.metrics.structK),
    avgFloor:avg(poor, t => t.metrics.organicFloor),
    avgMom:  avg(poor, t => t.metrics.mom4w),
    avgLift: avg(poor, t => t.dm.liftPct),
    n:       poor.length,
  } : null;
  return {
    n: withDM.length,
    successRate: withDM.length ? successful.length / withDM.length : null,
    avgLiftSuccess: avg(successful, t => t.dm.liftPct),
    avgLiftPoor:    avg(poor,       t => t.dm.liftPct),
    successProfile,
    poorProfile,
  };
};

// ════════════════════════════════════════════════════════════════
//  FORMATTERS
// ════════════════════════════════════════════════════════════════
const fmt = {
  // Short (1.2K, 3.4M) — for chart axes and compact KPIs
  k:(n)=>n>=1e6?`${(n/1e6).toFixed(1)}M`:n>=1e3?`${(n/1e3).toFixed(1)}K`:`${Math.round(n??0)}`,
  // Exact with thousands separator — for DM Audit numbers where precision matters
  exact:(n)=>Math.round(n??0).toLocaleString("es-AR"),
  pct:(n)=>`${n>0?"+":""}${(n??0).toFixed(1)}%`,
  usd:(n)=>`$${Math.abs(n??0).toLocaleString("en-US",{minimumFractionDigits:2,maximumFractionDigits:2})}`,
  dec4:(n)=>(n??0).toFixed(4),
};

